function report = runThreePlaneHeightTest(sceneNumber, options)
%RUNTHREEPLANEHEIGHTTEST Run min/mid/max height-plane ablation.
%
% This lightweight harness runs the unchanged raster-texture visualization
% pipeline with exactly three height labels: the minimum and maximum of the
% normal observability-bounded interval and their arithmetic midpoint. It
% does not run the full label grid or retune frozen SGM parameters.
%
% Example:
%   report = runThreePlaneHeightTest(6, NumWorkers=14);
%   report.LabelDiagnostics.SelectionFractions
%   report.Timing
%
% Traceability: docs/experiment_plan.md Stages 3, 5, and 6;
% algo/main.tex Algorithm 1 and Eqs. (71)--(76).

arguments
    sceneNumber (1, 1) double ...
        {mustBeFinite, mustBeInteger, ...
        mustBeMember(sceneNumber, 1:6)} = 6
    options.DatasetName (1, 1) string = "raster_texture_50m_v1"
    options.DatasetDirectory (1, 1) string = ""
    options.Display (1, 1) logical = true
    options.UseParallel (1, 1) logical = true
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.MaximumPendingTiles (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [128, 128]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 3
    options.CostCurveFraction (1, 2) double ...
        {mustBeFinite, mustBeGreaterThanOrEqual( ...
        options.CostCurveFraction, 0), mustBeLessThanOrEqual( ...
        options.CostCurveFraction, 1)} = [0.5, 0.5]
    options.StoreResearchCostVolumes (1, 1) logical = false
    options.CpuImplementation (1, 1) string ...
        {mustBeMember(options.CpuImplementation, ...
        ["optimized", "reference"])} = "optimized"
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
end

report = runRasterTextureVisualization(sceneNumber, ...
    DatasetName=options.DatasetName, ...
    DatasetDirectory=options.DatasetDirectory, ...
    Display=options.Display, UseParallel=options.UseParallel, ...
    NumWorkers=options.NumWorkers, ...
    MaximumPendingTiles=options.MaximumPendingTiles, ...
    TileSize=options.TileSize, LabelBlockSize=options.LabelBlockSize, ...
    CostCurveFraction=options.CostCurveFraction, ...
    StoreResearchCostVolumes=options.StoreResearchCostVolumes, ...
    CpuImplementation=options.CpuImplementation, ...
    WorkingPrecision=options.WorkingPrecision, ...
    HeightLabelMode="three-plane");

d = report.LabelDiagnostics;
fprintf("Three-plane height ablation\n");
fprintf("  labels [m]: %.6g, %.6g, %.6g\n", ...
    report.HeightLabelsMetres);
fprintf("  normal grid: %d labels; pixel-label reduction: %.3fx\n", ...
    d.ObservabilityDerivedLabelCount, d.PixelLabelReductionFactor);
fprintf("  one cost volume: %.3f MiB instead of %.3f MiB\n", ...
    d.ExecutedCostVolumeMiB, d.ObservabilityGridCostVolumeMiB);
fprintf("  guarded refinement valid on %.3f of raw-valid pixels\n", ...
    d.RefinementValidFractionOfRaw);
fprintf("  all adjacent SGM transitions capped: %s\n", ...
    string(d.AllSgmAdjacentTransitionsCapped));
disp(d.SelectionFractions);
end
